#include <bits/stdc++.h>
using namespace std;

string a,b;
string s[10][2];
int n,ans=11;
map<string,int> dis;

void dfs1(int dep,string str){
    if((dis.find(str)!=dis.end() && dis[str]<dep) || dep>6)
        return;
    dis[str]=dep;
    //cout<<str<<' '<<dep<<'\n';
    if(str==b)
    	return;
    for(int i=1;i<=n;i++){
        for(int j=0;j<=(int)(str.size())-(int)(s[i][0].size());j++)
            if(str.substr(j,s[i][0].size())==s[i][0]){
                string t=str;
				t=t.replace(j,s[i][0].size(),s[i][1]);
                dfs1(dep+1,t);
            }
    }
}

void dfs2(int dep,string str){
    if(dep>6 || dep>ans)
        return;
    //cout<<str<<' '<<dep<<'\n';
    if(dis.find(str)!=dis.end())
    	ans=min(ans,dis[str]+dep-2);
    if(str==a)
    	return;
    for(int i=1;i<=n;i++){
        for(int j=0;j<=(int)(str.size())-(int)(s[i][1].size());j++)
            if(str.substr(j,s[i][1].size())==s[i][1]){
                string t=str;
				t=t.replace(j,s[i][1].size(),s[i][0]);
                dfs2(dep+1,t);
            }
    }
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    cin>>a>>b;
    n=1;
    while(cin>>s[n][0]>>s[n][1])
		n++;
    n--;
    dfs1(1,a);
    dfs2(1,b);
    if(ans==11)
    	cout<<"NO ANSWER!";
    else
    	cout<<ans;
    return 0;
}
